// Haal de globale MID variabele op (message ID)
let mid = global.get("mid");

// Stel de constante Dev in
const Dev = "ASSET";

// Definieer de mapping van datatypes naar ID's
const idMapping = {
    "U1": 3000,
    "U2": 3100,
    "U3": 3200,
    "I1": 3300,
    "I2": 3400,
    "I3": 3500,
    "P1": 3600,
    "P2": 3700,
    "P3": 3800,
    "Q1": 3900,
    "Q2": 4000,
    "Q3": 4100,
    "PT": 4200,
    "QT": 4300,
    "PFT": 4400,
    "PExpT": 4500,
    "PImpT": 4600
};

//Maak mapping case-insensitive door keys ook in lowercase aan te spreken
const mappingLower = {};
Object.keys(idMapping).forEach(k => mappingLower[k.toLowerCase()] = idMapping[k]);

// Begin met het resultaat-object
let result = {
    MID: mid,
    D: [
        {
            Dev: Dev,
            ED: [],
            MD: []
        }
    ]
};

// Payload van binnenkomend bericht
const payloadData = msg.payload || {};
if (typeof payloadData !== "object") {
    node.warn("msg.payload is geen object");
}

// Loop door payload keys
for (let key in payloadData) {

    if (!payloadData.hasOwnProperty(key)) continue;

    // probeer eerst exacte key, anders case-insensitive match
    let id = idMapping[key];
    if (typeof id === "undefined") {
        id = mappingLower[key.toLowerCase()];
    }

    if (typeof id !== "undefined") {
        // Zorg dat de waarde een getal wordt: vervang komma -> punt en parse
        let rawVal = payloadData[key];
        // Als waarde een array / object / null is, skip
        if (rawVal === null || typeof rawVal === "object") {
            node.warn(`Overslaan ${key}: waarde is geen primitief (${typeof rawVal})`);
            continue;
        }
        let valStr = String(rawVal).trim().replace(",", ".");
        let num = parseFloat(valStr);
        if (!Number.isFinite(num)) {
            node.warn(`Ongeldige numerieke waarde voor ${key}: "${rawVal}" — overslaan`);
            continue;
        }

        result.D[0].MD.push({
            Id: id,
            Val: num
        });

    } else {
        // key niet in mapping 
        node.debug(`Key niet in mapping: ${key}`);
    }
}

// Voeg een timestamp toe in het juiste formaat
result.D[0].TS = new Date().toISOString();

// Alleen verhogen als we items toegevoegd hebben
if (result.D[0].MD.length > 0) {
    global.set("mid", mid + 1);
} 

// Stel de nieuwe payload in
msg.payload = result;
msg.queque = "success"
return msg;

if (msg.error) {
  msg.failReason = msg.error;
  return [null, msg];
}

if (!Array.isArray(msg.payload)) {
  msg.failReason = `payload_not_array (${typeof msg.payload})`;
  return [null, msg];
}

if (msg.payload.length !== 83) {
  msg.failReason = `bad_length (${msg.payload.length})`;
  return [null, msg];
}

if (msg.payload.every(v => v === 0)) {
  msg.failReason = "all_zero_payload";
  return [null, msg];
}

return [msg, null];

// ===== Modbus FAIL -> ED event wrapper =====

// 1) MID
let mid = global.get("mid") || 0;

// 2) Device
// Vul je echte asset-id in of haal uit msg (als je die meegeeft op fail-pad)
const Dev = "ASSET";

// 3) Event Id voor "modbus failure" (kies zelf een vrije ID)
const MODBUS_FAIL_EVENT_ID = 7199;

// 4) Reason bepalen (prioriteit: msg.failReason -> msg.error -> algemene fallback)
let reason = msg.failReason || msg.error || "MODBUS_FAIL";

// 5) Bouw extra context (unitId, queue length, topic, messageId)
const unitId = msg.unitId ?? msg.queueUnitId ?? (msg.queueLengthByUnitId?.unitId);
const qLen =
  msg.queueLengthByUnitId?.queueLength ??
  msg.queueLength ??
  undefined;

let details = [];
if (unitId !== undefined) details.push(`unitId=${unitId}`);
if (qLen !== undefined) details.push(`queueLen=${qLen}`);
if (msg.topic) details.push(`topic=${msg.topic}`);
if (msg.messageId) details.push(`messageId=${msg.messageId}`);

let val = String(reason);
if (details.length) val += ` | ${details.join(", ")}`;

// 6) Wrapper result
const result = {
  MID: mid,
  D: [
    {
      Dev: Dev,
      TS: new Date().toISOString(),
      ED: [
        {
          Id: MODBUS_FAIL_EVENT_ID,
          Val: val,   // <-- reden als tekst
          Sev: 4
        }
      ],
      MD: []
    }
  ]
};

// 7) MID ophogen (ik doe dit altijd voor fail-events)
global.set("mid", mid + 1);

// 8) Output
msg.payload = result;
msg.topic = "telemetry"; // als je dit verwacht downstream (optioneel)
msg.queque = "fail"
return msg;

const DELAY_MS = 7500;
const MAX_RETRY = 6;

const Dev = "ASSET";          
const RETRY_WARN_EVENT_ID = 7198;          

let q = (msg.queque || "").toLowerCase();
let retry = global.get("retry") || 0;

function sendLater(out1, out2, out3) {
  setTimeout(() => node.send([out1, out2, out3]), DELAY_MS);
}

// ---- FAIL ----
if (q === "fail") {
  retry += 1;
  global.set("retry", retry);

  // retry < 5 => output 1 ("go")
  if (retry < MAX_RETRY) {
    const m1 = {
      ...msg,
      action: "go",
      retry
    };
    sendLater(m1, null, null);
    return;
  }

  // retry >= 5 => na 5 sec: reset + output 2 ("stop/failover")
  global.set("retry", 0);

  const m2 = {
    ...msg,
    action: "stop",
    retry: MAX_RETRY
  };

  sendLater(null, m2, null);
  return;
}

// ---- SUCCESS ----
if (q === "success") {
  const retriesUsed = retry; 

  // Case A: success met <=1 retry => gewoon output 2 na 5 sec, reset
  if (retriesUsed <= 1) {
    global.set("retry", 0);

    const m2 = {
      ...msg,
      action: "ok",
      retry: 0
    };

    sendLater(null, m2, null);
    return;
  }

  // Case B: success maar met >1 retries => output 2 én output 3, reset
  global.set("retry", 0);

  // Output 2: control/success message
  const m2 = {
    ...msg,
    action: "ok_but_retried",
    info: `success but retried ${retriesUsed} times`,
    retriesUsed,
    retry: 0
  };

  // Output 3: ED event payload (severity 2)
  const mid = global.get("mid") || 0;
  global.set("mid", mid + 1);

  const m3 = {
    topic: "telemetry",
    queque: "event",
    payload: {
      MID: mid,
      D: [
        {
          Dev,
          TS: new Date().toISOString(),
          ED: [
            {
              Id: RETRY_WARN_EVENT_ID,
              Val: `success but retried ${retriesUsed} times`,
              Sev: 2
            }
          ],
          MD: []
        }
      ]
    }
  };

  sendLater(null, m2, m3);
  return;
}

const m2 = {
  ...msg,
  action: "unknown_queque",
  retry
};
sendLater(null, m2, null);
return;
